self.addEventListener("push",t=>{try{let{title:i,body:n,icon:e,data:o}=t.data.json();t.waitUntil(self.registration.showNotification(i,{body:n,icon:e||"/icons/icon-192x192.png",badge:"/icons/icon-192x192.png",vibrate:[200,100,200],data:o,actions:[{action:"open",title:"View UZZ \uD83C\uDF15"}]}))}catch(t){console.error("Push event error:",t)}}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data?.url||"/dashboard";t.waitUntil(clients.matchAll({type:"window"}).then(t=>{for(let n of t)if(n.url===i&&"focus"in n)return n.focus();if(clients.openWindow)return clients.openWindow(i)}))});